import torch

def get_gpu_info():
    """Détecte et retourne les informations GPU."""
    if not torch.cuda.is_available():
        return None, 0, "cpu"

    gpu_name = torch.cuda.get_device_name(0)
    gpu_memory = torch.cuda.get_device_properties(0).total_memory / 1e9
    return gpu_name, gpu_memory, "cuda"

def recommend_model(gpu_memory: float) -> str:
    """Recommande la variante SD3.5 selon la VRAM."""
    if gpu_memory >= 24:
        return "stabilityai/stable-diffusion-3.5-large"
    elif gpu_memory >= 16:
        return "stabilityai/stable-diffusion-3.5-large-turbo"
    elif gpu_memory >= 8:
        return "stabilityai/stable-diffusion-3.5-medium"
    return None

GPU_NAME, GPU_MEMORY, DEVICE = get_gpu_info()
RECOMMENDED_MODEL = recommend_model(GPU_MEMORY) if GPU_MEMORY else None
DTYPE = torch.float16 if GPU_MEMORY and GPU_MEMORY >= 16 else torch.bfloat16

if GPU_NAME:
    print(f"\n🎮 GPU: {GPU_NAME}")
    print(f"   VRAM: {GPU_MEMORY:.1f} GB")
    if RECOMMENDED_MODEL:
        print(f"   ✅ Recommandation: {RECOMMENDED_MODEL.split('/')[-1]}")
else:
    print("\n⚠️ Pas de GPU CUDA détecté")

# 2. Définition des Clients API

def generate_forge(prompt, seed=-1):
    payload = {
        "prompt": prompt,
        "steps": 4,        # SDXL-Lightning-4step (few-step distilled, #5867 option b)
        "width": 512,
        "height": 512,
        "cfg_scale": 1.5,
        "sampler_name": "Euler",  # forge sdapi: capital "Euler" (lowercase = HTTP 404, #5867)
        "seed": seed
    }
    try:
        start = time.time()
        resp = requests.post(f"{SERVICES['forge']['url']}/sdapi/v1/txt2img", json=payload, timeout=60)  # cold-start safety (#5867)
        duration = time.time() - start

        if resp.status_code == 200:
            img_data = base64.b64decode(resp.json()['images'][0])
            return Image.open(BytesIO(img_data)), duration
    except Exception as e:
        print(f"Forge Error: {e}")
    return None, 0

def generate_z_image(prompt, seed=42):
    # Workflow Qwen Image Edit fp8 (famille Lumina-2, #5867 — l'ancien workflow GGUF z_image_turbo
    # produisait des images vides ; ce workflow fp8 testé est celui du notebook 03-2).
    workflow = {
        "1": {"class_type": "VAELoader", "inputs": {"vae_name": "qwen_image_vae.safetensors"}},
        "2": {"class_type": "CLIPLoader", "inputs": {"clip_name": "qwen_2.5_vl_7b_fp8_scaled.safetensors", "type": "sd3"}},
        "3": {"class_type": "UNETLoader", "inputs": {"unet_name": "qwen_image_edit_2509_fp8_e4m3fn.safetensors", "weight_dtype": "fp8_e4m3fn"}},
        "4": {"class_type": "ModelSamplingAuraFlow", "inputs": {"model": ["3", 0], "shift": 3.0}},
        "5": {"class_type": "CFGNorm", "inputs": {"model": ["4", 0], "strength": 1.0}},
        "6": {"class_type": "TextEncodeQwenImageEdit", "inputs": {"clip": ["2", 0], "prompt": prompt[:300], "vae": ["1", 0]}},
        "7": {"class_type": "ConditioningZeroOut", "inputs": {"conditioning": ["6", 0]}},
        "8": {"class_type": "EmptySD3LatentImage", "inputs": {"width": 1024, "height": 1024, "batch_size": 1}},
        "9": {"class_type": "KSampler", "inputs": {"seed": seed, "steps": 12, "cfg": 1.0, "sampler_name": "euler", "scheduler": "beta", "denoise": 1.0, "model": ["5", 0], "positive": ["6", 0], "negative": ["7", 0], "latent_image": ["8", 0]}},
        "10": {"class_type": "VAEDecode", "inputs": {"samples": ["9", 0], "vae": ["1", 0]}},
        "11": {"class_type": "SaveImage", "inputs": {"images": ["10", 0], "filename_prefix": "Comp_Z"}}
    }

    headers = {"Authorization": f"Bearer {SERVICES['comfy']['token']}"}
    try:
        start = time.time()
        resp = requests.post(f"{SERVICES['comfy']['url']}/prompt", json={"prompt": workflow}, headers=headers, timeout=30)
        if resp.status_code != 200: return None, 0

        prompt_id = resp.json()['prompt_id']
        for _ in range(720):  # 12-min poll (cold-start Qwen fp8 ~6 min, #5867)
            hist = requests.get(f"{SERVICES['comfy']['url']}/history/{prompt_id}", headers=headers, timeout=30)
            if hist.status_code == 200:
                hj = hist.json()
                if prompt_id in hj:
                    status = hj[prompt_id].get("status", {})
                    if status.get("completed"):
                        outputs = hj[prompt_id].get("outputs", {})
                        for node_out in outputs.values():
                            for img_info in node_out.get("images", []):
                                img_resp = requests.get(f"{SERVICES['comfy']['url']}/view?filename={img_info['filename']}&subfolder={img_info.get('subfolder', '')}&type={img_info.get('type', 'output')}", headers=headers)
                                return Image.open(BytesIO(img_resp.content)), time.time() - start
            time.sleep(1)

    except Exception as e:
        print(f"Comfy Error: {e}")
    return None, 0

